#include <vector>
#include <queue>
using namespace std;

const int MOD = 1e9 + 7;

long long solve(std::vector<std::vector<long long>> grid) {
    int m = grid.size();
    if (m == 0) return 0;
    int n = grid[0].size();
    if (n == 0) return 0;

    vector<vector<long long>> dp(m, vector<long long>(n, 0));
    dp[0][0] = 1;

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (i == 0 && j == 0) continue;

            long long from_up = 0, from_left = 0;

            // Check path from up (i-1, j)
            if (i > 0) {
                int x = i-1, y = j;
                if (grid[x][y] == 1) {
                    // Down move was reflected to right
                    x = i;
                    y = j + 1;
                    if (y < n) {
                        from_up = dp[i-1][j];
                    }
                } else {
                    from_up = dp[i-1][j];
                }
            }

            // Check path from left (i, j-1)
            if (j > 0) {
                int x = i, y = j-1;
                if (grid[x][y] == 1) {
                    // Right move was reflected to down
                    x = i + 1;
                    y = j;
                    if (x < m) {
                        from_left = dp[i][j-1];
                    }
                } else {
                    from_left = dp[i][j-1];
                }
            }

            dp[i][j] = (from_up + from_left) % MOD;
        }
    }

    return dp[m-1][n-1];
}
